class Solution {
public:
    int maxTaskAssign(vector<int>& tasks, vector<int>& workers, int pills, int strength) {
        sort(tasks.begin(), tasks.end());
        sort(workers.begin(), workers.end());
        int left = 0, right = 0, res = 0;
        priority_queue<int, vector<int>, greater<int>> pq;
        while (left < tasks.size() && right < workers.size()) {
            if (workers[right] >= tasks[left]) {
                res++;
                left++;
                right++;
            } else if (pills > 0 && workers[right] + strength >= tasks[left]) {
                res++;
                pills--;
                left++;
                pq.push(workers[right]);
                right++;
            } else if (!pq.empty() && pq.top() + strength >= tasks[left]) {
                res++;
                left++;
                int top = pq.top(); pq.pop();
                pq.push(top + strength);
            } else {
                right++;
            }
        }
        return res;
    }
};
```
